### 实现Promise
```js
//原理
1. 三种状态 pedding fulfilled rejected
2. 实例then方法（静态方法、catch、finally 没实现)
3. 链式调用 

//实现
class Promise{
  constructor(fn){
    this.state = 'pedding';
    this.value = '';
    this.reason = '';

    let resolve = (value) =>{
       if(this.state == 'pedding'){
         this.state = 'fulfilled';
         this.value = value;
       }
    }

    let reject = (value) => {
       if(this.state == 'pedding'){
         this.state = 'rejected';
         this.reason = value;
       }
    }

    try{
      fn(resolve, reject);
    }catch(e){
      reject(e);
    }
  }

  then(onFulfilled, onRejected){
     switch(this.state){
        case 'fulfilled':
         onFulfilled(this.value);
         break
        case 'rejected':
          onRejected(this.value);
          break
     }
     return this;    //返回自身链式调用
  }
}
