//要求：12321、 1234321


//思路： 原数和倒序数相等则可以判断对称


//代码实现：
function reverse(n){
  let result = 0;
  //对数字依次求模，从右至左求出数字每一位
  while(n){
    result = result * 10 + n % 10;  //%10得到最后一位数，  %100得到最后二位数
    n = parseInt(n / 10);     //去除个位数其他的数
  }
  return result;
}

function isMirror(n){
  if(n === reverse(n))return true;
  return false;
}
