//实现
function compareVersion(curVer, oldVer){
   if(curVer && oldVer){
       let arr1 = curVer.split('.');
       let arr2 = oldVer.split('.');
       let minLen = Math.min(arr1.length, arr2.length);
       let position = 0;
       let diff = 0;

       //循环位数对比
       while(position < minLen){
