//题目
输入：1->2->3->4->null;
输出：4->3->2->1->null;
//思路
1. 把当前节点的next属性指向它的前一个节点


//实现
function listNode(val){
   this.val = val;   //当前节点
   this.next = null;  //该节点指向下一个节点
}

const reverseList = function (list){
   if(list === null || list.next === null){
       return list;
   }
   let pre = null, cur = list;
   while(cur !== null){
      let next = cur.next;  //保存临时变量
      cur.next = pre;  //当前节点next指向前一个
      pre = cur;
      cur = next;
   }

   return pre;
}

```
